tests:
def test_basic():
    result = full_justify(['This', 'is', 'an', 'example', 'of', 'text', 'justification.'], 16)
    assert result == ['This    is    an', 'example  of text', 'justification.  ']

def test_short():
    result = full_justify(['What', 'must', 'be', 'acknowledgment', 'shall', 'be'], 16)
    assert result == ['What   must   be', 'acknowledgment  ', 'shall be        ']

def test_long_words():
    result = full_justify(['Science', 'is', 'what', 'we', 'understand', 'well'], 20)
    assert len(result[0]) == 20

def test_single_word():
    result = full_justify(['word'], 10)
    assert result == ['word      ']

def test_exact_fit():
    result = full_justify(['ab', 'cd', 'ef'], 8)
    assert result == ['ab cd ef']

def test_one_word_per_line():
    result = full_justify(['abcdefghij'], 10)
    assert result == ['abcdefghij']
